def validate(args, output):
    nums = args[0]
    if not isinstance(output, list):
        return False
    from collections import Counter
    flat = []
    for row in output:
        if not isinstance(row, list):
            return False
        seen_in_row = set()
        for v in row:
            if v in seen_in_row:
                return False
            seen_in_row.add(v)
            flat.append(v)
    if Counter(flat) != Counter(nums):
        return False
    freq = Counter(nums)
    min_rows = max(freq.values()) if freq else 0
    if len(output) != min_rows:
        return False
    return True

