function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output)) return false;
    function counter(arr) {
        const m = new Map();
        for (const v of arr) m.set(v, (m.get(v) || 0) + 1);
        return m;
    }
    const flat = [];
    for (const row of output) {
        if (!Array.isArray(row)) return false;
        const seenInRow = new Set();
        for (const v of row) {
            if (seenInRow.has(v)) return false;
            seenInRow.add(v);
            flat.push(v);
        }
    }
    const a = counter(flat), b = counter(nums);
    if (a.size !== b.size) return false;
    for (const [k, v] of a) if (b.get(k) !== v) return false;
    let minRows = 0;
    for (const v of b.values()) if (v > minRows) minRows = v;
    if (output.length !== minRows) return false;
    return true;
}

