class Solution:
    def findMatrix(self, nums):
        from collections import Counter
        freq = Counter(nums)
        max_freq = max(freq.values()) if freq else 0
        rows = [[] for _ in range(max_freq)]
        for v in sorted(freq.keys()):
            c = freq[v]
            for r in range(c):
                rows[r].append(v)
        for row in rows:
            row.sort()
        rows.sort(key=lambda row: (-len(row), row))
        return rows

