class Solution:
    def findMatrix(self, nums):
        freq = {}
        rows = []
        for v in nums:
            r = freq.get(v, 0)
            if r == len(rows):
                rows.append([])
            rows[r].append(v)
            freq[v] = r + 1
        for row in rows:
            row.sort()
        rows.sort(key=lambda row: (-len(row), row))
        return rows

